import { execution } from '@dynatrace-sdk/automation-utils';
import { problemsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const response = await problemsClient.getProblem({
      problemId: input.problemId
    });

    console.log(`Retrieved problem details for ${input.problemId}`);

    return {
      problemId: response.problemId,
      displayId: response.displayId,
      title: response.title,
      description: response.description || 'No description',
      status: response.status,
      severity: response.severity,
      startTime: new Date(response.startTime).toISOString(),
      endTime: response.endTime ? new Date(response.endTime).toISOString() : null,
      rootCauseEntity: response.rootCauseEntity || null,
      affectedEntities: response.affectedEntities ? response.affectedEntities.length : 0,
      impactLevel: response.impactLevel || 'UNKNOWN'
    };
  } catch (error) {
    console.error('Error getting problem details:', error);
    throw new Error(`Failed to get problem details: ${error}`);
  }
}
